    reportParts[partIndex++] = `${txn.id}\t${txn.account}\tday=${txn.day}\t${label}\t${txn.amount}\tfee=${fee}\t${mark}\n`;
  }

  for (let c = 0; c < CATEGORIES; c++) {
    reportParts[partIndex++] = `TOTAL\t${categoryLabels[c]}\t${categoryTotals[c]}\n`;
  }
  reportParts[partIndex++] = `SUMMARY\tduplicates=${duplicates}\tflagged=${flagged}\tfees=${feeTotal}\n`;

  const report = reportParts.join("");
  writeFileSync(reportPath, report);

  return {
    duplicates,
    flagged,
    categoryTotals,
    feeTotal,
    reportLines: txns.length + CATEGORIES + 2,
    checksum: checksum(report),
  };
}

